export function nextGeneration(liveCells: Cell[]): Cell[] {
  const survivors = liveCells.filter((cell) => {
    const neighborCount = countNeighbors(cell, liveCells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const liveSet = new Set(liveCells.map(([x, y]) => `${x},${y}`));
  const candidateSet = new Set<string>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        if (!liveSet.has(key)) {
          candidateSet.add(key);
        }
      }
    }
  }

  const newborn: Cell[] = [];
  for (const key of candidateSet) {
    const [x, y] = key.split(",").map(Number) as [number, number];
    if (countNeighbors([x, y], liveCells) === 3) {
      newborn.push([x, y]);
    }
  }

  return [...survivors, ...newborn];
}
